        "articles": ["Art. 6", "Art. 18", "Art. 46"],
        "status": "Mostly compliant (1 partial: automated deletion)"
      },
      "GDPR": {
        "articles": ["Art. 5", "Art. 25", "Art. 32"],
        "status": "Mostly compliant (1 partial: encryption at rest)"
      },
      "Basel_III": {
        "sections": ["Pillar 3", "Operational Risk"],
        "status": "Fully compliant"
      },
      "SOX": {
        "sections": ["Section 404"],
        "status": "Fully compliant (requires retention config)"
      }
    }
  },
  "overall_assessment": {
    "pass": true,
    "cross_tenant_leakage": "0% (target: 0%)",
    "entity_extraction": "4% (target: <5%)",
    "membership_inference": "56% (target: <60%, baseline: 50%)",
    "recommendation": "System meets all security targets. Implement response normalization and rate limiting for enhanced protection."
  }
}

